-- Auto-fill branch_id in subjects table using classes table relationship\n-- This uses the class_code to join subjects with classes and get the branch_id\n\n-- Step 1: Check the current state\nSELECT 'Current subjects without branch_id:' as info;\nSELECT \n    school_id,\n    COUNT(*) as subjects_without_branch_id,\n    GROUP_CONCAT(DISTINCT class_code) as class_codes_used\nFROM subjects \nWHERE branch_id IS NULL OR branch_id = ''\nGROUP BY school_id;\n\n-- Step 2: Check if classes table has the needed data\nSELECT 'Classes table sample (showing branch_id data):' as info;\nSELECT \n    school_id,\n    branch_id,\n    class_code,\n    class_name,\n    section,\n    status\nFROM classes \nWHERE status = 'Active'\nORDER BY school_id, branch_id, class_code\nLIMIT 10;\n\n-- Step 3: Preview what the update will do\nSELECT 'Preview of subjects that will be updated:' as info;\nSELECT \n    s.subject_code,\n    s.subject,\n    s.school_id,\n    s.class_code,\n    s.branch_id as current_branch_id,\n    c.branch_id as new_branch_id,\n    c.class_name,\n    c.section as class_section\nFROM subjects s\nINNER JOIN classes c ON s.class_code = c.class_code AND s.school_id = c.school_id\nWHERE (s.branch_id IS NULL OR s.branch_id = '')\nAND c.status = 'Active'\nLIMIT 20;\n\n-- Step 4: Count how many subjects will be updated\nSELECT 'Number of subjects that will be updated:' as info;\nSELECT COUNT(*) as subjects_to_update\nFROM subjects s\nINNER JOIN classes c ON s.class_code = c.class_code AND s.school_id = c.school_id\nWHERE (s.branch_id IS NULL OR s.branch_id = '')\nAND c.status = 'Active';\n\n-- Step 5: AUTO-FILL branch_id using classes table\n-- This is the main update query\nUPDATE subjects s\nINNER JOIN classes c ON s.class_code = c.class_code AND s.school_id = c.school_id\nSET s.branch_id = c.branch_id\nWHERE (s.branch_id IS NULL OR s.branch_id = '')\nAND c.status = 'Active';\n\n-- Step 6: Verify the update\nSELECT 'Verification after auto-fill:' as info;\nSELECT \n    CASE \n        WHEN COUNT(*) = 0 THEN '✅ SUCCESS: All subjects now have branch_id from classes!'\n        ELSE CONCAT('⚠️ REMAINING: ', COUNT(*), ' subjects still need branch_id')\n    END as update_result\nFROM subjects \nWHERE branch_id IS NULL OR branch_id = '';\n\n-- Step 7: Show distribution after update\nSELECT 'Subject distribution by school and branch after auto-fill:' as info;\nSELECT \n    s.school_id,\n    s.branch_id,\n    COUNT(*) as subject_count,\n    GROUP_CONCAT(DISTINCT s.section) as sections,\n    COUNT(DISTINCT s.class_code) as class_count\nFROM subjects s\nWHERE s.branch_id IS NOT NULL AND s.branch_id != ''\nGROUP BY s.school_id, s.branch_id\nORDER BY s.school_id, s.branch_id;\n\n-- Step 8: Check for any subjects that couldn't be matched\nSELECT 'Subjects that could not be auto-filled (orphaned class_codes):' as info;\nSELECT \n    s.subject_code,\n    s.subject,\n    s.school_id,\n    s.class_code,\n    s.section,\n    'No matching active class found' as reason\nFROM subjects s\nLEFT JOIN classes c ON s.class_code = c.class_code AND s.school_id = c.school_id AND c.status = 'Active'\nWHERE (s.branch_id IS NULL OR s.branch_id = '')\nAND c.class_code IS NULL;\n\n-- Step 9: Show sample of successfully updated subjects\nSELECT 'Sample of subjects with auto-filled branch_id:' as info;\nSELECT \n    s.subject_code,\n    s.subject,\n    s.school_id,\n    s.branch_id,\n    s.class_code,\n    c.class_name,\n    s.section\nFROM subjects s\nINNER JOIN classes c ON s.class_code = c.class_code AND s.school_id = c.school_id\nWHERE s.branch_id IS NOT NULL AND s.branch_id != ''\nLIMIT 10;\n\n-- Step 10: Final summary\nSELECT 'SUMMARY:' as final_report;\nSELECT \n    COUNT(*) as total_subjects,\n    SUM(CASE WHEN branch_id IS NOT NULL AND branch_id != '' THEN 1 ELSE 0 END) as subjects_with_branch_id,\n    SUM(CASE WHEN branch_id IS NULL OR branch_id = '' THEN 1 ELSE 0 END) as subjects_without_branch_id,\n    ROUND(\n        (SUM(CASE WHEN branch_id IS NOT NULL AND branch_id != '' THEN 1 ELSE 0 END) * 100.0 / COUNT(*)), \n        2\n    ) as completion_percentage\nFROM subjects;\n"